4	// MARK: - Clock abstraction (testable time source)
5	
6	/// Abstracts `Date.now` so tests can inject a fixed point in time.
7	public protocol ClockProvider: Sendable {
8	    func now() -> Date
9	}
10	
11	public struct SystemClock: ClockProvider {
12	    public init() {}
13	    public func now() -> Date { Date() }
14	}
15	
16	// MARK: - Store
17	
18	/// Formats the active Claude account's time-window metrics for the menu bar.
19	/// Example: `S 48% 2h 13m | W 7% 6d 6h 13m`. Falls back to `"--"` when data is
20	/// unavailable, malformed, or no active account is found.
21	@Observable
22	@MainActor
23	public final class UsageStore {
24	    public private(set) var menuBarText: String = "--"
25	    /// Incremented each time handleNewData is called, whether the data is valid or malformed.
26	    /// Tests use this as a reliable signal that the store has consumed the latest yielded item.
27	    public private(set) var dataProcessedCount: Int = 0
28	    public private(set) var entries: [VendorUsageEntry] = []
29	
30	    // MARK: Dependencies
31	
32	    private let fileWatcher: FileWatching
33	    private let clock: ClockProvider
34	    private let logger: FileLogger
35	    private let countdownRefreshSeconds: UInt64
36	
37	    public static let defaultCountdownRefreshSeconds: UInt64 = 60
38	    private static let fallbackText = "--"
39	    private static let targetVendor: Vendor = .claude
40	    // Only top-level aggregate metrics belong in the compact menu bar label; per-model breakdowns live in the popover only
41	    private static let menuBarMetricNames: Set<String> = ["session", "weekly"]
42	
43	    // Latest decoded file kept for countdown refresh without re-reading disk
44	    private var lastFile: UsagesFile?
45	
46	    private var watchTask: Task<Void, Never>?
47	    private var countdownTask: Task<Void, Never>?
48	
49	    public init(
50	        fileWatcher: FileWatching,
51	        clock: ClockProvider = SystemClock(),
52	        logger: FileLogger = Loggers.app,
53	        countdownRefreshSeconds: UInt64 = UsageStore.defaultCountdownRefreshSeconds
54	    ) {
55	        self.fileWatcher = fileWatcher
56	        self.clock = clock
57	        self.logger = logger
58	        self.countdownRefreshSeconds = countdownRefreshSeconds
59	    }
60	
61	    // MARK: Lifecycle
62	
63	    /// Start watching the file and refreshing the countdown.
64	    /// Idempotent — calling again is a no-op.
65	    public func start() {
66	        guard watchTask == nil else { return }
67	
68	        let watcher = fileWatcher
69	        // Self is captured strongly; stop() cancels both tasks to break the cycle
70	        watchTask = Task { [self] in
71	            for await data in watcher.changes() {
72	                guard !Task.isCancelled else { break }
73	                self.handleNewData(data)
74	            }
75	        }
76	
77	        countdownTask = Task { [self] in
78	            let refreshNanos = self.countdownRefreshSeconds * 1_000_000_000
79	            while !Task.isCancelled {
80	                // CancellationError swallowed intentionally; checked on next loop iteration
81	                try? await Task.sleep(nanoseconds: refreshNanos)
82	                guard !Task.isCancelled else { break }
83	                self.refreshMenuBarText()
84	            }
85	        }
86	    }
87	
88	    /// Stop all background tasks. Idempotent.
89	    public func stop() {
90	        watchTask?.cancel()
91	        watchTask = nil
92	        countdownTask?.cancel()
93	        countdownTask = nil
94	    }
95	
96	    // Defensive: cancels tasks when the store is released without an explicit stop() call.
97	    @MainActor deinit { stop() }
98	
99	    // MARK: - Processing
100	
101	    private func handleNewData(_ data: Data) {
102	        dataProcessedCount += 1
103	        do {
104	            let file = try JSONDecoder().decode(UsagesFile.self, from: data)
105	            lastFile = file
106	            entries = file.usages
107	            menuBarText = format(file: file)
