import SwiftUI

/// A horizontal progress bar with an actual fill and a theoretical consumption marker.
/// The theoretical marker is a thin vertical tick showing expected consumption based on elapsed time.
struct GaugeBar: View {
    let actual: Double
    let theoretical: Double

    private static let barHeight: CGFloat = 6
    private static let markerWidth: CGFloat = 2.5
    private static let cornerRadius: CGFloat = 3

    var body: some View {
        GeometryReader { geo in
            let width = geo.size.width

            ZStack(alignment: .leading) {
                RoundedRectangle(cornerRadius: Self.cornerRadius)
                    .fill(.quaternary)

                RoundedRectangle(cornerRadius: Self.cornerRadius)
                    .fill(fillColor)
                    .frame(width: width * clamp(actual))

                // Skip marker when no window data — avoids a tick pinned to the left edge at 0.
                if theoretical > 0 {
                    RoundedRectangle(cornerRadius: Self.markerWidth / 2)
                        .fill(.primary)
                        .frame(width: Self.markerWidth, height: Self.barHeight + 4)
                        .offset(x: width * clamp(theoretical) - Self.markerWidth / 2)
                }
            }
        }
        .frame(height: Self.barHeight)
    }

    private var fillColor: Color {
        let clamped = clamp(actual)
        if clamped >= 0.9 { return .red }
        if clamped >= 0.75 { return .orange }
        return .accentColor
    }

    private func clamp(_ value: Double) -> CGFloat {
        CGFloat(min(max(value, 0), 1))
    }
}

import SwiftUI
import AIUsagesTrackersLib

/// Displays a time-window metric: name, gauge bar with theoretical marker,
/// percentage, remaining time, and next reset date.
struct TimeWindowMetricRow: View {
    let name: String
    let resetAt: ISODate
    let windowDuration: DurationMinutes
    let usagePercent: UsagePercent

    private var actualFraction: Double {
        Double(usagePercent.rawValue) / 100.0
    }

    var body: some View {
        let now = Date()

        VStack(alignment: .leading, spacing: 4) {
            HStack {
                Text(name.capitalized)
                    .font(.system(size: 11, weight: .medium))
                    .foregroundStyle(.secondary)
                Spacer()
                Text("\(usagePercent.rawValue)%")
                    .font(.system(size: 11, weight: .semibold).monospacedDigit())
            }

            GaugeBar(
                actual: actualFraction,
                theoretical: theoreticalFraction(resetAt: resetAt, windowDuration: windowDuration, now: now)
            )

            HStack {
                Text(formatRemainingTime(resetAt: resetAt, now: now))
                    .font(.system(size: 10).monospacedDigit())
                    .foregroundStyle(.secondary)
                Spacer()
                Text("resets \(formatResetDate(resetAt, now: now))")
                    .font(.system(size: 10))
                    .foregroundStyle(.secondary)
            }
        }
    }
}

import SwiftUI
import AppKit
import AIUsagesTrackersLib

@main
struct AIUsagesTrackersApp: App {
    private let poller: UsagePoller
    private let accountMonitor: ClaudeActiveAccountMonitor
    private let pidGuard: AppPidGuard
    @State private var usageStore: UsageStore

    init() {
        NSApplication.shared.setActivationPolicy(.accessory)

        let home = FileManager.default.homeDirectoryForCurrentUser.path
        let guard_ = AppPidGuard(cacheDir: "\(home)/.cache/ai-usages-tracker")
        do {
            try guard_.acquire()
        } catch AppPidGuardError.alreadyRunning(let pid, _) {
            let alert = NSAlert()
            alert.messageText = "AI Usages Tracker is already running"
            alert.informativeText = "Another instance is active (PID \(pid)). Use the menu bar icon to quit it before launching a new one."
            alert.runModal()
            NSApplication.shared.terminate(nil)
            fatalError("terminate() did not exit")
        } catch {
            let alert = NSAlert()
            alert.messageText = "Failed to start AI Usages Tracker"
            alert.informativeText = error.localizedDescription
            alert.runModal()
            NSApplication.shared.terminate(nil)
            fatalError("terminate() did not exit")
        }
        pidGuard = guard_

        let fileManager = UsagesFileManager.shared
        poller = UsagePoller(connectors: [ClaudeCodeConnector()], fileManager: fileManager)
        accountMonitor = ClaudeActiveAccountMonitor(fileManager: fileManager)

        let usagesPath = fileManager.filePath
        let fileWatcher = UsagesFileWatcher(path: usagesPath)
        let store = UsageStore(fileWatcher: fileWatcher)
        _usageStore = State(initialValue: store)

        let pollerRef = poller
        let monitorRef = accountMonitor
        Task { @MainActor in
            store.start()
            await pollerRef.start()
            await monitorRef.start()
        }
    }

    var body: some Scene {
        MenuBarExtra {
            UsageDetailsView(store: usageStore) {
                Task {
                    await poller.stop()
                    await accountMonitor.stop()
                }
                usageStore.stop()
                pidGuard.release()
                NSApplication.shared.terminate(nil)
            }
        } label: {
            Text(usageStore.menuBarText)
        }
        .menuBarExtraStyle(.window)
    }
}

