        #expect(result == nil)
    }

    @Test("zero actual percent returns ratio 0.0")
    func zeroActual() {
        let result = consumptionRatio(actualPercent: 0, theoreticalFraction: 0.5)
        #expect(result != nil)
        #expect(result! == 0.0)
    }
